/* Dimension TEI — design tokens v1.2.0
 * Paleta TEI canónica completa + capa semántica (--color-* usada por
 * todos los primitivos coloridos: alert, badge, banner, stat, kicker…).
 *
 * Aliases --tei-* preservados para los 79 primitivos del registry.
 */

:root {
  /* Tipografía */
  --tei-font-sans:    'Nunito', 'Segoe UI', system-ui, -apple-system, sans-serif;
  --tei-font-display: var(--tei-font-sans);
  --tei-font-mono:    'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;

  /* ─── Paleta base TEI ─────────────────────────────────────────── */

  --color-cyan-50:  #ecfaff;
  --color-cyan-100: #d4f4ff;
  --color-cyan-200: #aceaff;
  --color-cyan-300: #71daff;
  --color-cyan-400: #3dbdf2;
  --color-cyan-500: #1aa3e0;
  --color-cyan-600: #0086c2;
  --color-cyan-700: #0a6c9c;
  --color-cyan-800: #0f5980;
  --color-cyan-900: #134a6a;
  --color-cyan-950: #08293f;

  --color-blue-50:  #eef5ff;
  --color-blue-100: #d9e8ff;
  --color-blue-200: #b8d4ff;
  --color-blue-300: #8ab8ff;
  --color-blue-400: #5896ed;
  --color-blue-500: #1e96d4;
  --color-blue-600: #0f7bb5;
  --color-blue-700: #0e6294;
  --color-blue-800: #114e76;
  --color-blue-900: #133f5e;
  --color-blue-950: #08243a;

  --color-yellow-50:  #fff9e1;
  --color-yellow-100: #fff1b8;
  --color-yellow-200: #ffe27a;
  --color-yellow-300: #ffd03a;
  --color-yellow-400: #f5c333;
  --color-yellow-500: #e6ad17;
  --color-yellow-600: #c08a0f;
  --color-yellow-700: #946810;
  --color-yellow-800: #785214;
  --color-yellow-900: #614217;
  --color-yellow-950: #38240a;

  --color-coral-50:  #fff0ec;
  --color-coral-100: #ffded5;
  --color-coral-200: #ffbcaa;
  --color-coral-300: #ff9377;
  --color-coral-400: #f47155;
  --color-coral-500: #e85a3d;
  --color-coral-600: #c8421e;
  --color-coral-700: #a23115;
  --color-coral-800: #842a15;
  --color-coral-900: #6c2415;
  --color-coral-950: #3b0f08;

  --color-oxford-50:  #eef1f8;
  --color-oxford-100: #d9e0ee;
  --color-oxford-200: #b0bcd8;
  --color-oxford-300: #8294bd;
  --color-oxford-400: #56709d;
  --color-oxford-500: #34527c;
  --color-oxford-600: #213d63;
  --color-oxford-700: #16304f;
  --color-oxford-800: #0f223a;
  --color-oxford-900: #0b1733;
  --color-oxford-950: #050b1d;

  --color-ink-50:  #f8fafc;
  --color-ink-100: #eef2f7;
  --color-ink-200: #dde4ed;
  --color-ink-300: #c2cdd9;
  --color-ink-400: #94a1b3;
  --color-ink-500: #677589;
  --color-ink-600: #4a5468;
  --color-ink-700: #353d4f;
  --color-ink-800: #232a3a;
  --color-ink-900: #131a28;
  --color-ink-950: #080c14;

  /* ─── Tonos semánticos ────────────────────────────────────────── */

  --color-success-50:  #ecfdf3;
  --color-success-100: #d1fadf;
  --color-success-300: #6ce9a6;
  --color-success-500: #12b76a;
  --color-success-600: #039855;
  --color-success-700: #027a48;

  --color-warning-50:  var(--color-yellow-50);
  --color-warning-300: var(--color-yellow-300);
  --color-warning-500: var(--color-yellow-500);
  --color-warning-600: var(--color-yellow-600);
  --color-warning-700: var(--color-yellow-700);

  --color-danger-50:  var(--color-coral-50);
  --color-danger-300: var(--color-coral-300);
  --color-danger-500: var(--color-coral-500);
  --color-danger-600: var(--color-coral-600);
  --color-danger-700: var(--color-coral-700);

  --color-info-50:  var(--color-cyan-50);
  --color-info-300: var(--color-cyan-300);
  --color-info-500: var(--color-cyan-500);
  --color-info-600: var(--color-cyan-600);
  --color-info-700: var(--color-cyan-700);

  /* ─── Capa semántica light (default) ──────────────────────────── */

  --color-bg:          #ffffff;
  --color-bg-elevated: #ffffff;
  --color-bg-chrome:   #ffffff;
  --color-bg-subtle:   var(--color-ink-50);
  --color-bg-muted:    var(--color-ink-100);
  --color-bg-tinted:   rgb(26 163 224 / 0.10);
  --color-bg-overlay:  rgb(0 0 0 / 0.5);

  --color-text-primary:   var(--color-ink-900);
  --color-text-heading:   var(--color-ink-950);
  --color-text-secondary: var(--color-ink-700);
  --color-text-muted:     var(--color-ink-500);
  --color-text-disabled:  var(--color-ink-400);
  --color-text-inverse:   #ffffff;

  --color-border-subtle:  var(--color-ink-200);
  --color-border-default: var(--color-ink-300);
  --color-border-strong:  var(--color-ink-400);

  --color-brand:        var(--color-cyan-500);
  --color-brand-hover:  var(--color-cyan-600);
  --color-brand-soft:   var(--color-cyan-200);
  --color-brand-bg-soft: rgb(26 163 224 / 0.10);

  --color-focus-ring: var(--color-cyan-500);

  /* ─── Aliases --tei-* (compat con los 79 primitivos) ──────────── */

  --tei-bg:             var(--color-bg);
  --tei-bg-secondary:   var(--color-bg-subtle);
  --tei-surface:        var(--color-bg-elevated);
  --tei-surface-raised: var(--color-bg-elevated);

  --tei-border:        var(--color-border-subtle);
  --tei-border-strong: var(--color-border-default);

  --tei-text:        var(--color-text-primary);
  --tei-text-strong: var(--color-text-heading);
  --tei-muted:       var(--color-text-muted);

  --tei-accent:       var(--color-brand);
  --tei-accent-hover: var(--color-brand-hover);
  --tei-accent-fg:    var(--color-text-inverse);
  --tei-brand:        var(--color-cyan-400);
  --tei-brand-soft:   var(--color-brand-soft);

  --tei-success: var(--color-success-500);
  --tei-warning: var(--color-warning-500);
  --tei-danger:  var(--color-danger-500);
  --tei-info:    var(--color-info-500);

  --tei-focus-ring: var(--color-focus-ring);
  --tei-overlay:    var(--color-bg-overlay);

  /* Botones flotantes sobre imágenes — siempre oscuros en ambos temas */
  --tei-image-overlay:        rgb(0 0 0 / 0.65);
  --tei-image-overlay-strong: rgb(0 0 0 / 0.85);
  --tei-image-overlay-fg:     #ffffff;

  /* Editor de recorte — máscara y handles fijos */
  --tei-crop-mask:          rgb(0 0 0 / 0.45);
  --tei-crop-handle-bg:     #ffffff;
  --tei-crop-handle-border: rgb(0 0 0 / 0.6);

  /* Radios */
  --tei-radius-sm: 6px;
  --tei-radius-md: 8px;
  --tei-radius-lg: 12px;
  --tei-radius-xl: 16px;

  /* Sombras (basadas en oxford navy para coherencia) */
  --tei-shadow-sm: 0 1px 2px -1px rgb(11 23 51 / 0.05), 0 1px 3px 0 rgb(11 23 51 / 0.08);
  --tei-shadow-md: 0 4px 6px -2px rgb(11 23 51 / 0.05), 0 8px 16px -4px rgb(11 23 51 / 0.08);
  --tei-shadow-lg: 0 10px 15px -3px rgb(11 23 51 / 0.06), 0 20px 30px -10px rgb(11 23 51 / 0.10);

  --tei-transition-quick: 150ms ease;
}

/* ─── Tema oscuro · oxford navy híbrido (canónico TEI) ─────────── */
:root[data-theme="dark"],
:root.dark {
  --color-bg:          var(--color-oxford-800);
  --color-bg-elevated: var(--color-oxford-700);
  --color-bg-chrome:   var(--color-oxford-800);
  --color-bg-subtle:   var(--color-oxford-700);
  --color-bg-muted:    var(--color-oxford-600);
  --color-bg-tinted:   rgb(26 163 224 / 0.15);
  --color-bg-overlay:  rgb(0 0 0 / 0.7);

  --color-text-primary:   #ffffff;
  --color-text-heading:   #ffffff;
  --color-text-secondary: var(--color-ink-100);
  --color-text-muted:     var(--color-ink-300);
  --color-text-disabled:  var(--color-ink-400);
  --color-text-inverse:   var(--color-oxford-950);

  --color-border-subtle:  var(--color-oxford-600);
  --color-border-default: var(--color-oxford-500);
  --color-border-strong:  var(--color-oxford-400);

  --color-brand:         var(--color-cyan-400);
  --color-brand-hover:   var(--color-cyan-300);
  --color-brand-soft:    var(--color-cyan-300);
  --color-brand-bg-soft: rgb(26 163 224 / 0.20);

  --color-focus-ring: var(--color-cyan-300);

  /* tei-* aliases re-resuelven automáticamente vía var(--color-*) */
  --tei-accent-fg: var(--color-text-inverse);

  --tei-shadow-sm: 0 1px 2px rgb(0 0 0 / 0.25);
  --tei-shadow-md: 0 4px 16px rgb(0 0 0 / 0.35);
  --tei-shadow-lg: 0 12px 32px rgb(0 0 0 / 0.45);
}

/* Reducir movimiento */
:root[data-reduced-motion="true"] {
  --tei-transition-quick: unset;
}

/* ═══════════════════════════════════════════════════════════════
 * Utilidades visuales TEI (no Tailwind utilities, pero usables
 * con className desde cualquier componente del registry).
 * ═══════════════════════════════════════════════════════════════ */

/* Kicker — label tipográfico para etiquetas de sección */
.tei-kicker-cyan,
.tei-kicker-blue,
.tei-kicker-yellow,
.tei-kicker-coral,
.tei-kicker-ink {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  margin-bottom: 0.5rem;
  display: block;
}
.tei-kicker-cyan   { color: var(--color-cyan-700);   }
.tei-kicker-blue   { color: var(--color-blue-700);   }
.tei-kicker-yellow { color: var(--color-yellow-700); }
.tei-kicker-coral  { color: var(--color-coral-700);  }
.tei-kicker-ink    { color: var(--color-ink-700);    }
:root[data-theme="dark"] .tei-kicker-cyan,
:root.dark .tei-kicker-cyan      { color: var(--color-cyan-400);   }
:root[data-theme="dark"] .tei-kicker-blue,
:root.dark .tei-kicker-blue      { color: var(--color-blue-300);   }
:root[data-theme="dark"] .tei-kicker-yellow,
:root.dark .tei-kicker-yellow    { color: var(--color-yellow-400); }
:root[data-theme="dark"] .tei-kicker-coral,
:root.dark .tei-kicker-coral     { color: var(--color-coral-400);  }
:root[data-theme="dark"] .tei-kicker-ink,
:root.dark .tei-kicker-ink       { color: var(--color-ink-300);    }

/* Stripe — franja superior coloreada (Stat, Card destacada) */
.tei-stripe-cyan   { box-shadow: inset 0 4px 0 0 var(--color-cyan-500);   }
.tei-stripe-blue   { box-shadow: inset 0 4px 0 0 var(--color-blue-500);   }
.tei-stripe-yellow { box-shadow: inset 0 4px 0 0 var(--color-yellow-400); }
.tei-stripe-coral  { box-shadow: inset 0 4px 0 0 var(--color-coral-500);  }
.tei-stripe-ink    { box-shadow: inset 0 4px 0 0 var(--color-ink-700);    }
:root[data-theme="dark"] .tei-stripe-ink,
:root.dark .tei-stripe-ink { box-shadow: inset 0 4px 0 0 var(--color-ink-300); }

/* Gradient para palabras destacadas en titulares */
.text-gradient-cyan {
  background: linear-gradient(90deg, var(--color-cyan-500), var(--color-cyan-300));
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}

/* Fuentes corporativas — declaradas como @font-face nativas para poder
 * subsetear por unicode-range (latin / latin-ext) y minimizar el peso
 * descargado. Servidas desde /public/fonts (sin Google Fonts en runtime).
 *
 * Rangos copiados de la implementación oficial de Google Fonts. */

/* ─── Nunito ─────────────────────────────────────────────────────────── */

@font-face {
  font-family: 'Nunito';
  font-style: normal;
  font-weight: 400;
  font-display: swap;
  src: url('/fonts/nunito-latin-400-normal.woff2') format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+2074, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}
@font-face {
  font-family: 'Nunito';
  font-style: normal;
  font-weight: 400;
  font-display: swap;
  src: url('/fonts/nunito-latin-ext-400-normal.woff2') format('woff2');
  unicode-range: U+0100-024F, U+0259, U+1E00-1EFF, U+2020, U+20A0-20AB, U+20AD-20C0, U+2113, U+2C60-2C7F, U+A720-A7FF;
}

@font-face {
  font-family: 'Nunito';
  font-style: italic;
  font-weight: 400;
  font-display: swap;
  src: url('/fonts/nunito-latin-400-italic.woff2') format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+2074, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}
