/* ─── JetBrains Mono ─────────────────────────────────────────────────── */
/* font-display: optional para evitar reflow en bloques de código que
 * aparecen tarde en el render. Si no llega a tiempo se usa el fallback
 * monospace y el bloque mantiene su tamaño. */

@font-face {
  font-family: 'JetBrains Mono';
  font-style: normal;
  font-weight: 400;
  font-display: optional;
  src: url('/fonts/jetbrains-mono-latin-400-normal.woff2') format('woff2');
